sql:
SELECT AVG((base_price + dynamic_price_factor) * total_passengers) AS average_ticket_price
FROM flights
JOIN bookings ON flights.flight_id = bookings.flight_id;

SELECT COUNT(notification_id) AS total_read_notifications
FROM notifications
WHERE customer_id = 'CUSTOMER_ID' AND is_read = 1;

external_knowledge:
- The term "how each is doing" refers to the number of bookings and the total revenue;
- "Airlines" in this context corresponds to the airline company names;
- "Booking numbers" refers to the count of bookings made;
- "Money they've brought in" means the total revenue generated from ticket sales.

sql:
SELECT c.*
FROM customers c
WHERE EXISTS (SELECT 1 FROM bookings b WHERE b.customer_id = c.customer_id);

SELECT c.first_name, c.last_name, c.email
FROM customers c
JOIN bookings b ON c.customer_id = b.customer_id;

SELECT first_name, last_name, email
FROM customers
WHERE customer_id NOT IN (
   SELECT DISTINCT customer_id
   FROM bookings
);
